     5→ */
     6→
     7→import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
     8→import { db, schema } from '../db/client';
     9→import { eq, and, desc } from 'drizzle-orm';
    10→
    11→interface RecommendBody {
    12→  serviceId: string;
    13→  date: string;
    14→  constraints?: {
    15→    prioritizeBalancing?: boolean;
    16→    maxDeadRunningKm?: number;
    17→  };
    18→}
    19→
    20→interface AllocationBody {
    21→  serviceId: string;
    22→  trainId: string;
    23→  date: string;
    24→  score?: number;
    25→  justifications?: string[];
    26→}
    27→
    28→interface AllocationQueryParams {
    29→  date?: string;
    30→  status?: 'pending' | 'confirmed' | 'completed' | 'cancelled';
    31→}
    32→
    33→export async function allocationsRoutes(fastify: FastifyInstance) {
    34→  // GET /api/allocations
    35→  fastify.get('/', async (request: FastifyRequest<{ Querystring: AllocationQueryParams }>, reply: FastifyReply) => {
    36→    try {
    37→      const { date, status } = request.query;
    38→
    39→      const conditions = [];
    40→      if (date) conditions.push(eq(schema.allocations.allocationDate, date));
    41→      if (status) conditions.push(eq(schema.allocations.status, status));
    42→
    43→      const allocations = await db.query.allocations.findMany({
    44→        where: conditions.length > 0 ? and(...conditions) : undefined,
    45→        with: {
    46→          service: true,
    47→          train: true,
    48→        },
    49→        orderBy: [desc(schema.allocations.createdAt)],
    50→        limit: 100,
    51→      });
    52→
    53→      return { allocations };
    54→    } catch (error) {
    55→      request.log.error(error);
    56→      reply.status(500).send({ error: 'Failed to fetch allocations' });
    57→    }
    58→  });
    59→
    60→  // POST /api/allocations/recommend
    61→  fastify.post('/recommend', async (request: FastifyRequest<{ Body: RecommendBody }>, reply: FastifyReply) => {
    62→    try {
    63→      const { serviceId, date, constraints } = request.body;
    64→
    65→      // Get the service details
    66→      const service = await db.query.services.findFirst({
    67→        where: eq(schema.services.id, serviceId),
    68→      });
    69→
    70→      if (!service) {
    71→        return reply.status(404).send({ error: 'Service not found' });
    72→      }
    73→
    74→      // Call the Python solver service
    75→      const solverUrl = process.env.SOLVER_URL || 'http://localhost:8000';
    76→
    77→      try {
    78→        const response = await fetch(`${solverUrl}/recommend`, {
    79→          method: 'POST',
    80→          headers: { 'Content-Type': 'application/json' },
    81→          body: JSON.stringify({
    82→            service_id: serviceId,
    83→            date,
    84→            constraints: constraints || { prioritize_balancing: true },
    85→          }),
    86→        });
    87→
    88→        if (response.ok) {
    89→          const data = await response.json();
    90→          return data;
    91→        }
    92→      } catch (solverError) {
    93→        request.log.warn('Solver unavailable, using fallback');
    94→      }
    95→
    96→      // Ranking by km (prioritize under-running trains for mileage balancing)
    97→      const trains = await db.query.trains.findMany({
    98→        where: eq(schema.trains.fitnessStatus, 'fit'),
    99→        orderBy: [schema.trains.currentKm],
   100→        limit: 5,
   101→      });
   102→
   103→      const avgKm = trains.reduce((sum, t) => sum + t.currentKm, 0) / trains.length;
   104→
   105→      const recommendations = trains.map((train, idx) => ({
   106→        trainId: train.id,
   107→        train_id: train.trainId,
